request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?orgId
  ?orgName
  ?corpusId
  (COUNT(DISTINCT ?model) AS ?modelCount)
  (MIN(?created) AS ?earliestModel)
  (MAX(?created) AS ?latestModel)
  (GROUP_CONCAT(DISTINCT ?modelName; separator=", ") AS ?modelNames)
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(STR(?orgId) = "67e70970f0404a7e87122700ad26d87b")
  OPTIONAL { ?org rdfs:label ?orgName . }
  OPTIONAL { ?org tai:belongsTo ?corpus . }
  OPTIONAL { ?corpus tai:corpusId ?corpusId . }

  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .
}
GROUP BY ?orgId ?orgName ?corpusId
LIMIT 25
